#!/usr/bin/env node
/**
 * URL loading tests for SyncPlay v0.6 FR-2 fix.
 * Runs Playwright in headless Chromium against the static-served client.
 */
'use strict';

const { chromium } = require('playwright');
const path = require('path');

const BASE = 'http://127.0.0.1:8765/client/index.html';
const TEST_VIDEO_LOCAL_ABS = '/Users/bruce/CodeProjects/syncplay/src/client/test-video.mp4';
// Public sample videos
const URL_HTTPS = 'https://commondatastorage.googleapis.com/gtv-videos-bucket/sample/BigBuckBunny.mp4';
const URL_HTTP = 'http://commondatastorage.googleapis.com/gtv-videos-bucket/sample/BigBuckBunny.mp4';
// HLS public sample (Apple bipbop)
const URL_M3U8 = 'https://devstreaming-cdn.apple.com/videos/streaming/examples/bipbop_16x9/bipbop_16x9_variant.m3u8';

const results = [];
function record(id, desc, pass, detail) {
  results.push({ id, desc, pass, detail });
  const tag = pass ? '✅ PASS' : '❌ FAIL';
  console.log(`${tag} ${id}: ${desc}`);
  if (detail) console.log(`   → ${detail}`);
}

async function newPage(browser) {
  const ctx = await browser.newContext();
  const page = await ctx.newPage();
  page.on('pageerror', (e) => console.log(`  [pageerror] ${e.message}`));
  page.on('console', (m) => {
    if (m.type() === 'error') console.log(`  [console.error] ${m.text()}`);
  });
  // Capture errors that are caught by the app's error handler
  await page.exposeFunction('__reportToast', (msg) => {
    console.log(`  [toast] ${msg}`);
  });
  return page;
}

async function gotoApp(page) {
  await page.goto(BASE, { waitUntil: 'domcontentloaded', timeout: 15000 });
  // Wait for the video element to exist
  await page.waitForSelector('#videoUrlInput', { timeout: 5000 });
  // Wait for the app to bind DOM (give it a tick)
  await page.waitForTimeout(200);
}

async function loadUrlAndWait(page, url, timeoutMs = 25000) {
  // Install a one-shot listener for either 'loadedmetadata' or 'error' on the video
  await page.evaluate(() => {
    window.__videoResult = null;
    const v = document.getElementById('video');
    const finish = (type, info) => {
      if (window.__videoResult) return;
      window.__videoResult = { type, info, t: Date.now() };
    };
    v.addEventListener('loadedmetadata', () => finish('loadedmetadata', {
      duration: v.duration, videoWidth: v.videoWidth, videoHeight: v.videoHeight,
      error: v.error ? { code: v.error.code, message: v.error.message } : null,
    }), { once: true });
    v.addEventListener('error', () => finish('error', {
      error: v.error ? { code: v.error.code, message: v.error.message } : null,
    }), { once: true });
  });

  await page.fill('#videoUrlInput', url);
  await page.click('#loadUrlBtn');

  try {
    await page.waitForFunction(() => window.__videoResult !== null, null, { timeout: timeoutMs });
  } catch (e) {
    return { type: 'timeout', error: { code: null, message: 'no loadedmetadata/error within ' + timeoutMs + 'ms' } };
  }
  return await page.evaluate(() => window.__videoResult);
}

async function testHttps(browser) {
  console.log('\n=== Test 1.1/1.2/1.3: HTTPS / HTTP / 跨域 URL (BigBuckBunny) ===');
  const page = await newPage(browser);
  try {
    await gotoApp(page);
    const result = await loadUrlAndWait(page, URL_HTTPS, 30000);
    console.log('  result:', JSON.stringify(result, null, 2));
    if (result.type === 'loadedmetadata') {
      const ok = result.info.duration > 0 && result.info.videoWidth > 0;
      record('1.1', 'HTTPS URL 正常播放', ok,
        ok ? `loadedmetadata OK, duration=${result.info.duration}s, ${result.info.videoWidth}x${result.info.videoHeight}` : 'duration/width 异常');
    } else {
      record('1.1', 'HTTPS URL 正常播放', false, `error code=${result.error?.code} msg=${result.error?.message}`);
    }
  } catch (e) {
    record('1.1', 'HTTPS URL 正常播放', false, 'exception: ' + e.message);
  } finally {
    await page.context().close();
  }
}

async function testHttp(browser) {
  console.log('\n=== Test 1.2: HTTP URL (mixed content expected to fail in some envs) ===');
  const page = await newPage(browser);
  try {
    await gotoApp(page);
    const result = await loadUrlAndWait(page, URL_HTTP, 20000);
    console.log('  result:', JSON.stringify(result, null, 2));
    if (result.type === 'loadedmetadata') {
      record('1.2', 'HTTP URL 正常播放', true, `duration=${result.info.duration}s`);
    } else if (result.type === 'error') {
      // On https page, http video may be blocked by mixed content
      record('1.2', 'HTTP URL 正常播放 (注: GitHub Pages 服务 https, http 走 mixed content)', null,
        `error code=${result.error?.code} (mixed content 限制为浏览器策略, 非 app bug)`);
    } else {
      record('1.2', 'HTTP URL 正常播放', null, `timeout (服务可能不可达)`);
    }
  } catch (e) {
    record('1.2', 'HTTP URL 正常播放', null, 'exception: ' + e.message);
  } finally {
    await page.context().close();
  }
}

async function testCorsSame(browser) {
  console.log('\n=== Test 1.3: 跨域 URL (Google CDN, CORS 允许) ===');
  // Reuse HTTPS test, since BigBuckBunny is also cross-origin
  const page = await newPage(browser);
  try {
    await gotoApp(page);
    const result = await loadUrlAndWait(page, URL_HTTPS, 30000);
    if (result.type === 'loadedmetadata') {
      record('1.3', '跨域 URL (CORS 允许) 正常播放', true,
        `BigBuckBunny is cross-origin, duration=${result.info.duration}s`);
    } else {
      record('1.3', '跨域 URL (CORS 允许) 正常播放', false,
        `error code=${result.error?.code} msg=${result.error?.message}`);
    }
  } catch (e) {
    record('1.3', '跨域 URL (CORS 允许) 正常播放', false, 'exception: ' + e.message);
  } finally {
    await page.context().close();
  }
}

async function testFileLocal(browser) {
  console.log('\n=== Test 1.4: file:// 本地视频 (用 fileInput change 模拟) ===');
  const page = await newPage(browser);
  try {
    await page.goto(BASE, { waitUntil: 'domcontentloaded' });
    await page.waitForSelector('#videoInput');
    // Set file via setInputFiles
    await page.setInputFiles('#videoInput', TEST_VIDEO_LOCAL_ABS);
    // Wait for loadedmetadata
    await page.evaluate(() => {
      window.__videoResult = null;
      const v = document.getElementById('video');
      v.addEventListener('loadedmetadata', () => {
        window.__videoResult = { type: 'loadedmetadata',
          info: { duration: v.duration, videoWidth: v.videoWidth, videoHeight: v.videoHeight, error: v.error?.code || null } };
      }, { once: true });
      v.addEventListener('error', () => {
        window.__videoResult = { type: 'error', info: { error: v.error?.code || null } };
      }, { once: true });
    });
    await page.waitForFunction(() => window.__videoResult !== null, null, { timeout: 10000 });
    const r = await page.evaluate(() => window.__videoResult);
    console.log('  result:', JSON.stringify(r, null, 2));
    if (r.type === 'loadedmetadata') {
      record('1.4', '本地 file:// 视频仍能加载', true,
        `duration=${r.info.duration}s, ${r.info.videoWidth}x${r.info.videoHeight}`);
    } else {
      record('1.4', '本地 file:// 视频仍能加载', false, 'error code=' + r.info.error);
    }
  } catch (e) {
    record('1.4', '本地 file:// 视频仍能加载', false, 'exception: ' + e.message);
  } finally {
    await page.context().close();
  }
}

async function testM3u8(browser) {
  console.log('\n=== Test 1.5: m3u8 / HLS 流 (Apple BipBop) ===');
  const page = await newPage(browser);
  try {
    await gotoApp(page);
    // First check canPlayType
    const canHls = await page.evaluate(() => ({
      apple: document.getElementById('video').canPlayType('application/vnd.apple.mpegurl'),
      generic: document.getElementById('video').canPlayType('application/x-mpegURL'),
    }));
    console.log('  canPlayType result:', JSON.stringify(canHls));
    const result = await loadUrlAndWait(page, URL_M3U8, 20000);
    console.log('  result:', JSON.stringify(result, null, 2));
    if (result.type === 'loadedmetadata') {
      record('1.5', 'm3u8/hls 流能正常播放', true,
        `loadedmetadata OK, duration=${result.info.duration}s (canPlayType apple="${canHls.apple}", generic="${canHls.generic}")`);
    } else if (result.type === 'error') {
      // If browser doesn't support HLS, Builder's HLS check should have warned
      const hasHlsSupport = canHls.apple !== '' || canHls.generic !== '';
      record('1.5', 'm3u8/hls 流能正常播放 (注: Chrome/Firefox 需 hls.js)',
        null,
        `canPlayType: apple="${canHls.apple}" generic="${canHls.generic}" → ${hasHlsSupport ? 'supports' : 'no native support'}, error code=${result.error?.code}`);
    } else {
      record('1.5', 'm3u8/hls 流能正常播放', null, 'timeout');
    }
  } catch (e) {
    record('1.5', 'm3u8/hls 流能正常播放', null, 'exception: ' + e.message);
  } finally {
    await page.context().close();
  }
}

(async () => {
  const browser = await chromium.launch({ headless: true });
  try {
    await testHttps(browser);
    await testHttp(browser);
    await testCorsSame(browser);
    await testFileLocal(browser);
    await testM3u8(browser);
  } finally {
    await browser.close();
  }

  console.log('\n========== SUMMARY ==========');
  const passed = results.filter((r) => r.pass === true).length;
  const failed = results.filter((r) => r.pass === false).length;
  const nulls = results.filter((r) => r.pass === null).length;
  for (const r of results) {
    const tag = r.pass === true ? '✅' : r.pass === false ? '❌' : '⚠️';
    console.log(`${tag} ${r.id} — ${r.desc}`);
  }
  console.log(`\nPASS=${passed} FAIL=${failed} SKIP/N-A=${nulls}`);
  process.exit(failed > 0 ? 1 : 0);
})();

