async function test_4_no_regression(browser) {
  console.log('\n=== Test 4.1-4.2: 不破坏现有功能 (本地视频选择 + 房间创建/加入) ===');
  // 4.1 本地视频: 已经测过 (1.4) — 重测以确保它仍可工作
  const page = await newPage(browser);
  try {
    await page.goto(PAGE_BASE, { waitUntil: 'domcontentloaded' });
    await page.waitForSelector('#videoInput');
    await page.waitForSelector('#createBtn');
    await page.waitForSelector('#joinBtn');
    await page.waitForSelector('#roomIdInput');

    // 4.1: 本地视频 (file input) — 复测
    await page.setInputFiles('#videoInput', TEST_VIDEO_LOCAL_ABS);
    await page.evaluate(() => {
      window.__videoResult = null;
      const v = document.getElementById('video');
      v.addEventListener('loadedmetadata', () => { window.__videoResult = 'ok'; }, { once: true });
      v.addEventListener('error', () => { window.__videoResult = 'err'; }, { once: true });
    });
    await page.waitForFunction(() => window.__videoResult !== null, null, { timeout: 10000 });
    const r = await page.evaluate(() => window.__videoResult);
    record('4.1', '现有本地视频选择功能仍正常', r === 'ok', `file input → loadedmetadata: ${r}`);

    // 4.2: 房间创建/加入 — 只检查 UI 元素存在 + 按钮可点 (不实际连 PeerJS, 那不在本任务范围)
    const roomUI = await page.evaluate(() => {
      const create = document.getElementById('createBtn');
      const join = document.getElementById('joinBtn');
      const input = document.getElementById('roomIdInput');
      return {
        createExists: !!create, createDisabled: create?.disabled,
        joinExists: !!join, joinDisabled: join?.disabled,
        inputExists: !!input, inputDisabled: input?.disabled,
      };
    });
    console.log('  room UI:', JSON.stringify(roomUI));
    const ok = roomUI.createExists && roomUI.joinExists && roomUI.inputExists
            && !roomUI.createDisabled && !roomUI.joinDisabled && !roomUI.inputDisabled;
    record('4.2', '房间创建/加入功能不受影响 (UI 元素仍存在 + 可点)', ok,
      `createExists=${roomUI.createExists}, joinExists=${roomUI.joinExists}, inputExists=${roomUI.inputExists}`);

    // Bonus: 检查 4.2 中"创建房间"按钮的 click 不抛错 (网络会失败但 JS 路径正常)
    let clickError = null;
    page.on('pageerror', (e) => { clickError = e.message; });
    await page.fill('#roomIdInput', 'test-room-123');
    // 不真点 (会触发 PeerJS 连接, 噪音), 但用 JS dispatch click 验证 onclick handler 不 throw
    const clickOk = await page.evaluate(() => {
      try {
        document.getElementById('joinBtn').click();
        return true;
      } catch (e) { return e.message; }
    });
    record('4.2.bonus', 'joinBtn click handler 不抛 JS 错', clickOk === true, `result=${clickOk}`);
  } catch (e) {
    record('4.1', '现有本地视频选择功能仍正常', false, 'exception: ' + e.message);
  } finally {
    await page.context().close();
  }
}

(async () => {
  const browser = await chromium.launch({ headless: true });
  try {
    await test_1_1_https(browser);
    await test_1_3_cors(browser);
    await test_1_4_file(browser);
    await test_1_5_m3u8(browser);
    await test_2_error_handling(browser);
    await test_3_metadata(browser);
    await test_4_no_regression(browser);
  } finally {
    await browser.close();
  }

  console.log('\n========== SUMMARY ==========');
  const passed = results.filter((r) => r.pass === true).length;
  const failed = results.filter((r) => r.pass === false).length;
  const skipped = results.filter((r) => r.pass === null).length;
  for (const r of results) {
    const tag = r.pass === true ? '✅' : r.pass === false ? '❌' : '⚠️';
    console.log(`${tag} ${r.id} — ${r.desc}`);
  }
  console.log(`\nPASS=${passed} FAIL=${failed} N/A=${skipped} TOTAL=${results.length}`);
  // Write report to file for the test report
  const fs = require('fs');
  fs.writeFileSync('/tmp/syncplay-test-results.json', JSON.stringify(results, null, 2));
  process.exit(failed > 0 ? 1 : 0);
})();

