    const r = await page.evaluate(() => window.__videoResult);
    console.log('  result:', JSON.stringify(r, null, 2));
    if (r.type === 'loadedmetadata') {
      record('1.4', '本地 file:// 视频仍能加载', true,
        `duration=${r.info.duration}s, ${r.info.videoWidth}x${r.info.videoHeight}`);
    } else {
      record('1.4', '本地 file:// 视频仍能加载', false, `error code=${r.info.errCode}`);
    }
  } catch (e) {
    record('1.4', '本地 file:// 视频仍能加载', false, 'exception: ' + e.message);
  } finally {
    await page.context().close();
  }
}

async function test_1_5_m3u8(browser) {
  console.log('\n=== Test 1.5: m3u8 / HLS 流 (本地 .m3u8) ===');
  const page = await newPage(browser);
  try {
    await gotoApp(page);
    const canHls = await page.evaluate(() => ({
      apple: document.getElementById('video').canPlayType('application/vnd.apple.mpegurl'),
      generic: document.getElementById('video').canPlayType('application/x-mpegURL'),
    }));
    console.log('  canPlayType:', JSON.stringify(canHls));
    const result = await loadUrlAndWait(page, LOCAL_M3U8, 10000);
    console.log('  result:', JSON.stringify(result, null, 2));
    const toastText = await page.evaluate(() => {
      const t = document.getElementById('toast');
      return t ? t.textContent : null;
    });
    console.log('  toast text:', toastText);
    const hasHlsSupport = canHls.apple !== '' || canHls.generic !== '';
    if (result.type === 'loadedmetadata') {
      record('1.5', 'm3u8/hls 流能正常播放', true,
        `Chromium 支持 HLS ("maybe"), duration=${result.info.duration}s`);
    } else if (result.type === 'error') {
      if (hasHlsSupport) {
        record('1.5', 'm3u8/hls 流能正常播放', null,
          `canPlayType="maybe" 但 m3u8 内容失败 (本地 .m3u8 引用 mp4 不是标准 HLS, error code=${result.info.errCode})`);
      } else {
        record('1.5', 'm3u8/hls 流能正常播放 (浏览器不支持 HLS)', true,
          `toast 提示触发: "${toastText}" — Builder 的 HLS 检测逻辑工作正常`);
      }
    } else {
      record('1.5', 'm3u8/hls 流能正常播放', null, `timeout (result=${JSON.stringify(result)})`);
    }
  } catch (e) {
    record('1.5', 'm3u8/hls 流能正常播放', false, 'exception: ' + e.message);
  } finally {
    await page.context().close();
  }
}

async function test_2_error_handling(browser) {
  console.log('\n=== Test 2.1-2.3: 错误处理 (404 URL) ===');
  const page = await newPage(browser);
  try {
    await gotoApp(page);
    const r1 = await loadUrlAndWait(page, 'http://127.0.0.1:8765/nonexistent.mp4', 8000);
    console.log('  404 result:', JSON.stringify(r1, null, 2));
    const t1 = await page.evaluate(() => {
      const t = document.getElementById('toast');
      return t ? t.textContent : null;
    });
    console.log('  404 toast:', t1);
    if (r1.type === 'error') {
      const hasSpecificReason = t1 && t1.includes('加载失败:') && t1.length > 6;
      record('2.1', 'URL 加载失败时 UI 显示清晰错误提示', hasSpecificReason, `toast="${t1}"`);
      record('2.2', '错误提示包含失败原因 (不只"加载失败")',
        hasSpecificReason && t1.length > '视频加载失败: '.length,
        `toast="${t1}" (length=${t1 ? t1.length : 0})`);
      const suggestsAction = t1 && (t1.includes('URL') || t1.includes('检查') || t1.includes('网络') || t1.includes('CORS') || t1.includes('不支持'));
      record('2.3', '用户能根据错误提示知道怎么修', suggestsAction, `toast 含 actionable 信息: ${suggestsAction}`);
    } else {
      record('2.1', 'URL 加载失败时 UI 显示清晰错误提示', false, `期望 error, 实际 ${r1.type}`);
    }
  } catch (e) {
    record('2.1', 'URL 加载失败时 UI 显示清晰错误提示', false, 'exception: ' + e.message);
  } finally {
    await page.context().close();
  }
}

async function test_3_metadata(browser) {
  console.log('\n=== Test 3.1-3.3: 元数据读取 ===');
  const page = await newPage(browser);
  try {
    await gotoApp(page);
    const result = await loadUrlAndWait(page, LOCAL_VIDEO_8765, 10000);
    console.log('  result:', JSON.stringify(result, null, 2));
    if (result.type === 'loadedmetadata') {
      record('3.1', '加载成功后 video.duration 可读', isFinite(result.info.duration) && result.info.duration > 0,
        `duration=${result.info.duration}`);
      record('3.2', '加载成功后 video.videoWidth/Height 可读',
        result.info.videoWidth > 0 && result.info.videoHeight > 0,
        `${result.info.videoWidth}x${result.info.videoHeight}`);
      record('3.3', '元数据加载触发 loadedmetadata 事件', true,
        'loadedmetadata event fired (whole test hinges on it)');
    } else {
      record('3.1', '加载成功后 video.duration 可读', false, 'no loadedmetadata');
      record('3.2', '加载成功后 video.videoWidth/Height 可读', false, 'no loadedmetadata');
      record('3.3', '元数据加载触发 loadedmetadata 事件', false, 'no loadedmetadata');
    }
    const fileNameText = await page.evaluate(() => document.getElementById('fileName').textContent);
    console.log('  fileName text:', fileNameText);
  } catch (e) {
    record('3.1', '加载成功后 video.duration 可读', false, 'exception: ' + e.message);
  } finally {
    await page.context().close();
  }
}

async function test_4_no_regression(browser) {
  console.log('\n=== Test 4.1-4.2: 不破坏现有功能 ===');
  const page = await newPage(browser);
  try {
    await page.goto(PAGE_BASE, { waitUntil: 'domcontentloaded' });
    await page.waitForSelector('#videoInput');
    await page.waitForSelector('#createBtn');
    await page.waitForSelector('#joinBtn');
    await page.waitForSelector('#roomIdInput');

    await page.setInputFiles('#videoInput', TEST_VIDEO_LOCAL_ABS);
    await page.evaluate(() => {
      window.__videoResult = null;
      const v = document.getElementById('video');
      v.addEventListener('loadedmetadata', () => { window.__videoResult = 'ok'; }, { once: true });
      v.addEventListener('error', () => { window.__videoResult = 'err'; }, { once: true });
    });
    await page.waitForFunction(() => window.__videoResult !== null, null, { timeout: 10000 });
    const r = await page.evaluate(() => window.__videoResult);
    record('4.1', '现有本地视频选择功能仍正常', r === 'ok', `file input → loadedmetadata: ${r}`);

    const roomUI = await page.evaluate(() => {
      const create = document.getElementById('createBtn');
      const join = document.getElementById('joinBtn');
      const input = document.getElementById('roomIdInput');
      return {
        createExists: !!create, createDisabled: create && create.disabled,
        joinExists: !!join, joinDisabled: join && join.disabled,
        inputExists: !!input, inputDisabled: input && input.disabled,
      };
    });
    console.log('  room UI:', JSON.stringify(roomUI));
    const ok = roomUI.createExists && roomUI.joinExists && roomUI.inputExists
            && !roomUI.createDisabled && !roomUI.joinDisabled && !roomUI.inputDisabled;
    record('4.2', '房间创建/加入功能不受影响 (UI 元素仍存在 + 可点)', ok,
      `createExists=${roomUI.createExists}, joinExists=${roomUI.joinExists}, inputExists=${roomUI.inputExists}`);
  } catch (e) {
    record('4.1', '现有本地视频选择功能仍正常', false, 'exception: ' + e.message);
  } finally {
    await page.context().close();
  }
}

(async () => {
  const browser = await chromium.launch({ headless: true });
  try {
    await test_1_1_https(browser);
    await test_1_3_cors(browser);
    await test_1_4_file(browser);
    await test_1_5_m3u8(browser);
    await test_2_error_handling(browser);
    await test_3_metadata(browser);
    await test_4_no_regression(browser);
  } finally {
    await browser.close();
  }

  console.log('\n========== SUMMARY ==========');
  const passed = results.filter((r) => r.pass === true).length;
  const failed = results.filter((r) => r.pass === false).length;
  const skipped = results.filter((r) => r.pass === null).length;
  for (const r of results) {
    const tag = r.pass === true ? '✅' : r.pass === false ? '❌' : '⚠️';
    console.log(`${tag} ${r.id} — ${r.desc}`);
  }
  console.log(`\nPASS=${passed} FAIL=${failed} N/A=${skipped} TOTAL=${results.length}`);
  const fs = require('fs');
  fs.writeFileSync('/tmp/syncplay-test-results.json', JSON.stringify(results, null, 2));
  process.exit(failed > 0 ? 1 : 0);
})();

