1	// SyncPlay - 客户端核心逻辑
2	// 重构版本 v2：修复同步状态机 + 漂移校准 + 断线重连
3	
4	(function () {
5	  'use strict';
6	
7	  // 从独立模块加载 SyncEngine（浏览器通过 window.SyncPlay，Node 可直接 require）
8	  const { SyncEngine } = window.SyncPlay || {};
9	
10	  // ============ 配置 ============
11	  const CONFIG = {
12	    // PeerJS 服务器地址（默认走官方公共服务器，可改为自建）
13	    PEER_HOST: '0.peerjs.com',
14	    PEER_PORT: 443,
15	    PEER_PATH: '/',
16	    PEER_SECURE: true,
17	
18	    // 重连参数
19	    RECONNECT_DELAY_MS: 2000,
20	    MAX_RECONNECT_ATTEMPTS: 5,
21	  };
22	
23	  // ============ ICE 服务器配置 ============
24	  // 📌 加载顺序(config 文件必须在 app.js 之前):
25	  //    1. config.local.js   (git 忽略,放真凭据,可选)
26	  //    2. config.template.js (占位符,必备)
27	  //    3. app.js            (本文件,读 window.SYNCPLAY_ICE_SERVERS)
28	  // 📌 如果两个 config 文件都加载失败(理论不应发生),用最后的兜底占位符
29	  //    这种情况下 TURN 中继不会工作,只能 STUN 直连。
30	  const ICE_SERVERS = window.SYNCPLAY_ICE_SERVERS || [
31	    { urls: 'stun:global.relay.metered.ca:80' },
32	    { urls: 'turn:global.relay.metered.ca:80',  username: '__TURN_USERNAME__', credential: '__TURN_CREDENTIAL__' },
33	    { urls: 'turn:global.relay.metered.ca:443', username: '__TURN_USERNAME__', credential: '__TURN_CREDENTIAL__' },
34	    { urls: 'turns:global.relay.metered.ca:443', username: '__TURN_USERNAME__', credential: '__TURN_CREDENTIAL__' },
35	  ];
36	
37	  // ============ 工具函数 ============
38	
39	  /** 用 crypto 生成房间号（密码学安全） */
40	  function generateRoomId() {
41	    if (window.crypto && window.crypto.randomUUID) {
42	      return 'room-' + window.crypto.randomUUID().split('-')[0];
43	    }
44	    return 'room-' + Math.random().toString(36).substring(2, 10);
45	  }
46	
47	  /** Toast 通知（替代 alert） */
48	  function toast(msg, type = 'info') {
49	    let el = document.getElementById('toast');
50	    if (!el) {
51	      el = document.createElement('div');
52	      el.id = 'toast';
53	      el.className = 'toast';
54	      document.body.appendChild(el);
55	    }
56	    el.textContent = msg;
57	    el.className = 'toast show ' + type;
58	    clearTimeout(toast._t);
